it("should return premium of 5 G for empty item list (processing fee only)", () => {
  const scenario = {
    customer: { yearsWithMHPCO: 0 },
    steps: [{ op: "quote", items: [] }],
  };
  const result = processScenario(scenario);
  expect(result.results[0].premium).toBe(5);
});

